# Runs the cw-decoder against every WAV in a stress-test directory
# (typically generated by stress-gen.ps1) and prints a degradation
# summary: per-variant final WPM, decoded transcript length, and
# (optionally) CER vs an expected/known transcript.
#
# Usage:
#   .\stress-eval.ps1 -StressDir data\cw-stress\30wpm
#   .\stress-eval.ps1 -StressDir data\cw-stress\30wpm -Truth (Get-Content -Raw data\cw-stress\30wpm\TRUTH.txt)
#   .\stress-eval.ps1 -StressDir data\cw-stress\30wpm -MinTonePurity 0  # gate disabled
#
# Output is human-readable to stdout plus a CSV at <StressDir>\stress-results.csv.
[CmdletBinding()]
param(
  [Parameter(Mandatory)] [string] $StressDir,
  [string] $DecoderExe = 'experiments\cw-decoder\target\release\cw-decoder.exe',
  [double] $MinTonePurity = 3.0,
  [string] $Truth = '',
  [switch] $RangeLock,
  [double] $RangeLockMinHz = 350,
  [double] $RangeLockMaxHz = 1100
)

$ErrorActionPreference = 'Stop'

if (-not (Test-Path -LiteralPath $StressDir)) {
  throw "Stress dir not found: $StressDir"
}
if (-not (Test-Path -LiteralPath $DecoderExe)) {
  throw "Decoder not built. Run: cargo build --manifest-path experiments\cw-decoder\Cargo.toml --release --bin cw-decoder"
}

# Conservative Levenshtein for CER. Good enough for the small transcripts
# we feed it (a few hundred chars at most).
function Get-LevenshteinDistance {
  param([string] $A, [string] $B)
  if ([string]::IsNullOrEmpty($A)) { return $B.Length }
  if ([string]::IsNullOrEmpty($B)) { return $A.Length }
  $m = $A.Length; $n = $B.Length
  $prev = New-Object 'int[]' ($n + 1)
  $curr = New-Object 'int[]' ($n + 1)
  for ($j = 0; $j -le $n; $j++) { $prev[$j] = $j }
  for ($i = 1; $i -le $m; $i++) {
    $curr[0] = $i
    for ($j = 1; $j -le $n; $j++) {
      $cost = if ($A[$i-1] -eq $B[$j-1]) { 0 } else { 1 }
      $curr[$j] = [Math]::Min(
        [Math]::Min($curr[$j-1] + 1, $prev[$j] + 1),
        $prev[$j-1] + $cost)
    }
    for ($j = 0; $j -le $n; $j++) { $prev[$j] = $curr[$j] }
  }
  return $prev[$n]
}

$wavs = Get-ChildItem -LiteralPath $StressDir -Filter '*.wav' | Sort-Object Name
if ($wavs.Count -eq 0) { throw "No WAVs in $StressDir" }

$truthNorm = ($Truth -replace '\s+', ' ').Trim().ToUpperInvariant()
$haveTruth = -not [string]::IsNullOrEmpty($truthNorm)

$results = @()
$decoderArgs = @('--min-tone-purity', $MinTonePurity)
if ($RangeLock) {
  $decoderArgs += @(
    '--experimental-range-lock',
    '--range-lock-min-hz', $RangeLockMinHz,
    '--range-lock-max-hz', $RangeLockMaxHz)
}

Write-Host "Decoder:  $DecoderExe"
Write-Host "Variants: $($wavs.Count)"
Write-Host "Purity:   $MinTonePurity   (RangeLock=$($RangeLock.IsPresent))"
if ($haveTruth) { Write-Host "Truth:    $($truthNorm.Length) chars" }
Write-Host ''

# Header
$fmt = "{0,-30}  {1,6}  {2,5}  {3,5}  {4,7}  {5}"
Write-Host ($fmt -f 'variant', 'pitch', 'wpm', 'chars', 'cer', 'transcript (first 80)') -ForegroundColor Yellow
Write-Host ('-' * 100)

foreach ($wav in $wavs) {
  $cliArgs = @('stream-file', $wav.FullName) + $decoderArgs
  $raw  = & $DecoderExe @cliArgs 2>&1
  $rawText = $raw -join "`n"

  $pitch = '-'
  $m = [regex]::Match($rawText, 'Final pitch:\s+(\S+)\s+Hz')
  if ($m.Success) { $pitch = $m.Groups[1].Value }

  $wpm = '-'
  $m = [regex]::Match($rawText, 'Final WPM:\s+(\S+)')
  if ($m.Success -and $m.Groups[1].Value -ne '(none)') { $wpm = $m.Groups[1].Value }

  $transcript = ''
  $m = [regex]::Match($rawText, '(?ms)Transcript:\s*\r?\n(.*)$')
  if ($m.Success) { $transcript = $m.Groups[1].Value }
  $transcriptNorm = ($transcript -replace '\s+', ' ').Trim().ToUpperInvariant()
  $chars = $transcriptNorm.Length

  $cer = '-'
  $cerNum = $null
  if ($haveTruth -and $chars -gt 0) {
    $dist = Get-LevenshteinDistance $truthNorm $transcriptNorm
    $cerNum = $dist / [Math]::Max(1, $truthNorm.Length)
    $cer  = '{0:F2}' -f $cerNum
  }

  $preview = if ($transcriptNorm.Length -gt 80) { $transcriptNorm.Substring(0, 80) + '...' } else { $transcriptNorm }
  $color = if ($wpm -eq '-' -or $chars -lt 5) { 'Red' }
           elseif ($null -ne $cerNum -and $cerNum -gt 0.3) { 'Yellow' }
           else { 'Green' }
  Write-Host ($fmt -f $wav.BaseName, $pitch, $wpm, $chars, $cer, $preview) -ForegroundColor $color

  $results += [pscustomobject]@{
    variant     = $wav.BaseName
    pitch_hz    = $pitch
    wpm         = $wpm
    char_count  = $chars
    cer         = $cer
    transcript  = $transcriptNorm
  }
}

$csv = Join-Path $StressDir 'stress-results.csv'
$results | Export-Csv -LiteralPath $csv -NoTypeInformation -Encoding UTF8
Write-Host ''
Write-Host "Wrote $csv" -ForegroundColor Green
